import { useState, useMemo } from 'react';
import { PEOPLE_MOCK, type Person } from '@/mocks/people';
import EntitiesHero from './components/EntitiesHero';
import EntitiesFilters, { type EntityTypeFilter, type EntitySortOption } from './components/EntitiesFilters';
import EntitiesGrid from './components/EntitiesGrid';
import Sidebar from '@/components/feature/Sidebar';
import { useScrollReveal } from '@/hooks/useScrollReveal';

const ALL_ENTITIES = Object.values(PEOPLE_MOCK);

function matchesType(person: Person, type: EntityTypeFilter): boolean {
  if (type === 'all') return true;
  return person.role.toLowerCase().includes(type);
}

function matchesSearch(person: Person, query: string): boolean {
  if (!query.trim()) return true;
  const q = query.toLowerCase();
  return (
    person.name.toLowerCase().includes(q) ||
    person.role.toLowerCase().includes(q) ||
    person.nationality.toLowerCase().includes(q) ||
    person.known_for.some(k => k.toLowerCase().includes(q)) ||
    person.works.some(w => w.title.toLowerCase().includes(q))
  );
}

function getAvgRating(works: Person['works']): number {
  if (!works.length) return 0;
  return works.reduce((s, w) => s + w.rating, 0) / works.length;
}

function sortEntities(entities: Person[], sortBy: EntitySortOption): Person[] {
  return [...entities].sort((a, b) => {
    switch (sortBy) {
      case 'works_desc':
        return b.works.length - a.works.length;
      case 'works_asc':
        return a.works.length - b.works.length;
      case 'rating_desc':
        return getAvgRating(b.works) - getAvgRating(a.works);
      case 'name_asc':
        return a.name.localeCompare(b.name);
      case 'name_desc':
        return b.name.localeCompare(a.name);
      default:
        return 0;
    }
  });
}

// Type distribution for the sidebar stats
function getTypeStats(entities: Person[]) {
  const counts: Record<string, number> = {};
  entities.forEach(e => {
    const key = e.role.toLowerCase();
    counts[key] = (counts[key] ?? 0) + 1;
  });
  return counts;
}

const TYPE_LABELS: Record<string, { label: string; icon: string; color: string }> = {
  actor: { label: 'Actores', icon: 'ri-user-smile-line', color: 'text-amber-500' },
  actriz: { label: 'Actrices', icon: 'ri-user-heart-line', color: 'text-teal-500' },
  'actor/actriz': { label: 'Actor/Actriz', icon: 'ri-user-heart-line', color: 'text-teal-500' },
  director: { label: 'Directores', icon: 'ri-movie-2-line', color: 'text-orange-500' },
  autor: { label: 'Autores', icon: 'ri-quill-pen-line', color: 'text-emerald-500' },
  desarrollador: { label: 'Estudios', icon: 'ri-gamepad-line', color: 'text-cyan-500' },
  publisher: { label: 'Publishers', icon: 'ri-building-2-line', color: 'text-slate-500' },
  artista: { label: 'Artistas', icon: 'ri-music-2-line', color: 'text-sky-500' },
};

export default function EntitiesPage() {
  const [search, setSearch] = useState('');
  const [activeType, setActiveType] = useState<EntityTypeFilter>('all');
  const [sortBy, setSortBy] = useState<EntitySortOption>('works_desc');
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [showAll, setShowAll] = useState(false);

  // Sidebar reveal refs
  const sidebarTypeRef = useScrollReveal<HTMLDivElement>();
  const sidebarTopRef = useScrollReveal<HTMLDivElement>({ rootMargin: '0px 0px -20px 0px' });
  const sidebarStatsRef = useScrollReveal<HTMLDivElement>({ rootMargin: '0px 0px -20px 0px' });

  const PAGE_SIZE = 24;

  const filtered = useMemo(() => {
    const base = ALL_ENTITIES.filter(
      e => matchesType(e, activeType) && matchesSearch(e, search)
    );
    return sortEntities(base, sortBy);
  }, [search, activeType, sortBy]);

  const displayed = showAll ? filtered : filtered.slice(0, PAGE_SIZE);

  const typeStats = useMemo(() => getTypeStats(ALL_ENTITIES), []);

  // Top entity by works
  const topEntity = useMemo(
    () => [...ALL_ENTITIES].sort((a, b) => b.works.length - a.works.length)[0],
    []
  );

  return (
    <div className="min-h-screen bg-[var(--bg)] dark:bg-[var(--bg)]">
      <Sidebar />

      <EntitiesHero
        search={search}
        onSearchChange={v => { setSearch(v); setShowAll(false); }}
        totalCount={ALL_ENTITIES.length}
      />

      <EntitiesFilters
        activeType={activeType}
        onTypeChange={t => { setActiveType(t); setShowAll(false); }}
        sortBy={sortBy}
        onSortChange={s => { setSortBy(s); setShowAll(false); }}
        viewMode={viewMode}
        onViewModeChange={setViewMode}
        resultCount={filtered.length}
      />

      <div className="max-w-screen-xl mx-auto px-4 md:px-6 py-8">
        <div className="flex gap-8">
          {/* Main content */}
          <div className="flex-1 min-w-0">
            <EntitiesGrid entities={displayed} viewMode={viewMode} />

            {/* Load more */}
            {!showAll && filtered.length > PAGE_SIZE && (
              <div className="mt-8 flex justify-center">
                <button
                  onClick={() => setShowAll(true)}
                  className="flex items-center gap-2 px-6 py-3 rounded-xl bg-zinc-900 dark:bg-white text-white dark:text-zinc-900 text-sm font-semibold hover:opacity-90 transition-opacity cursor-pointer whitespace-nowrap"
                >
                  <i className="ri-add-line"></i>
                  Ver {filtered.length - PAGE_SIZE} más
                </button>
              </div>
            )}
          </div>

          {/* Sidebar */}
          <aside className="hidden xl:flex flex-col gap-5 w-64 flex-shrink-0">
            {/* Distribution by type */}
            <div
              ref={sidebarTypeRef}
              className="sr-item bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-100 dark:border-zinc-800 p-5"
            >
              <h3
                className="text-sm font-bold text-zinc-900 dark:text-white mb-4"
                style={{ fontFamily: "'Space Grotesk', sans-serif" }}
              >
                Por tipo
              </h3>
              <div className="flex flex-col gap-2.5">
                {Object.entries(typeStats)
                  .sort(([, a], [, b]) => b - a)
                  .map(([type, count]) => {
                    const meta = TYPE_LABELS[type];
                    if (!meta) return null;
                    const pct = Math.round((count / ALL_ENTITIES.length) * 100);
                    return (
                      <button
                        key={type}
                        onClick={() => setActiveType(type as EntityTypeFilter)}
                        className="w-full text-left cursor-pointer group"
                      >
                        <div className="flex items-center justify-between mb-1">
                          <div className="flex items-center gap-1.5">
                            <i className={`${meta.icon} text-xs ${meta.color}`}></i>
                            <span className="text-xs font-medium text-zinc-700 dark:text-zinc-300 group-hover:text-zinc-900 dark:group-hover:text-white transition-colors">
                              {meta.label}
                            </span>
                          </div>
                          <span className="text-xs font-bold text-zinc-500">{count}</span>
                        </div>
                        <div className="h-1.5 bg-zinc-100 dark:bg-zinc-800 rounded-full overflow-hidden">
                          <div
                            className="h-full rounded-full transition-all duration-500"
                            style={{ width: `${pct}%`, background: 'linear-gradient(90deg, #f43f5e, #fb923c)' }}
                          />
                        </div>
                      </button>
                    );
                  })}
              </div>
            </div>

            {/* Top entity */}
            {topEntity && (
              <div
                ref={sidebarTopRef}
                className="sr-item bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-100 dark:border-zinc-800 overflow-hidden"
              >
                <div className="relative h-28 overflow-hidden">
                  <img src={topEntity.backdrop} alt={topEntity.name} className="w-full h-full object-cover object-top" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent" />
                  <div className="absolute bottom-2 left-3">
                    <span className="text-xs font-semibold text-amber-400 flex items-center gap-1">
                      <i className="ri-trophy-line"></i> Más prolífico
                    </span>
                  </div>
                </div>
                <div className="p-4 flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl overflow-hidden flex-shrink-0">
                    <img src={topEntity.photo} alt={topEntity.name} className="w-full h-full object-cover object-top" />
                  </div>
                  <div className="min-w-0">
                    <p className="text-sm font-bold text-zinc-900 dark:text-white truncate" style={{ fontFamily: "'Space Grotesk', sans-serif" }}>
                      {topEntity.name}
                    </p>
                    <p className="text-xs text-zinc-500">{topEntity.works.length} obras en catálogo</p>
                  </div>
                </div>
              </div>
            )}

            {/* Quick stats */}
            <div
              ref={sidebarStatsRef}
              className="sr-item bg-white dark:bg-zinc-900 rounded-2xl border border-zinc-100 dark:border-zinc-800 p-5"
            >
              <h3
                className="text-sm font-bold text-zinc-900 dark:text-white mb-4"
                style={{ fontFamily: "'Space Grotesk', sans-serif" }}
              >
                Estadísticas
              </h3>
              <div className="flex flex-col gap-3">
                {[
                  {
                    label: 'Rating medio global',
                    value: (ALL_ENTITIES.flatMap(e => e.works).reduce((s, w) => s + w.rating, 0) / ALL_ENTITIES.flatMap(e => e.works).length).toFixed(1),
                    icon: 'ri-star-line',
                    color: 'text-amber-500',
                  },
                  {
                    label: 'Obras totales',
                    value: ALL_ENTITIES.flatMap(e => e.works).length,
                    icon: 'ri-film-line',
                    color: 'text-brand dark:text-brand-dark',
                  },
                  {
                    label: 'Entidades activas',
                    value: ALL_ENTITIES.length,
                    icon: 'ri-group-line',
                    color: 'text-cyan-500',
                  },
                ].map(stat => (
                  <div key={stat.label} className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <i className={`${stat.icon} text-sm ${stat.color}`}></i>
                      <span className="text-xs text-zinc-500">{stat.label}</span>
                    </div>
                    <span className="text-sm font-bold text-zinc-900 dark:text-white">{stat.value}</span>
                  </div>
                ))}
              </div>
            </div>
          </aside>
        </div>
      </div>
    </div>
  );
}
